package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormat_withNormalValues() {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormat_withNullValue() {
        CSVFormat formatWithNullString = csvFormat.withNullString("NULL");
        String result = formatWithNullString.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    public void testFormat_withEmptyValues() {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    public void testFormat_withQuoteCharacter() {
        CSVFormat formatWithQuote = csvFormat.withQuote('"');
        String result = formatWithQuote.format("a,b", "c\"d", "e");
        assertTrue(result.contains("\"a,b\""));
        assertTrue(result.contains("\"c\"\"d\""));
    }

    @Test
    public void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Use reflection to invoke private method and simulate IOException in CSVPrinter.printRecord
        StringWriter mockWriter = mock(StringWriter.class);
        doThrow(new IOException("mock IO exception")).when(mockWriter).write(any(char[].class), anyInt(), anyInt());

        // Create a subclass to override CSVPrinter creation to inject mockWriter
        CSVFormat format = new CSVFormat(',', '"', null, null, null, false, true,
                "\r\n", null, null, null, false, false, false) {
            @Override
            public String format(Object... values) {
                try {
                    // forcibly create CSVPrinter with mockWriter to cause IOException
                    new CSVPrinter(mockWriter, this).printRecord(values);
                    return mockWriter.toString().trim();
                } catch (IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> format.format("a"));
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("mock IO exception", thrown.getCause().getMessage());
    }
}
